import pytest

from your_module import topological_sort


def test_topological_sort_happy_path_simple_dag():
    graph = {
        "A": ["B", "C"],
        "B": ["D"],
        "C": ["D"],
        "D": [],
    }

    result = topological_sort(graph)

    assert set(result) == {"A", "B", "C", "D"}
    assert result.index("A") < result.index("B")
    assert result.index("A") < result.index("C")
    assert result.index("B") < result.index("D")
    assert result.index("C") < result.index("D")


def test_topological_sort_happy_path_multiple_valid_orders():
    graph = {
        "A": ["C"],
        "B": ["C"],
        "C": [],
    }

    result = topological_sort(graph)

    assert set(result) == {"A", "B", "C"}
    assert result.index("A") < result.index("C")
    assert result.index("B") < result.index("C")


def test_topological_sort_empty_graph():
    assert topological_sort({}) == []


def test_topological_sort_single_node_no_edges():
    graph = {"A": []}

    assert topological_sort(graph) == ["A"]


def test_topological_sort_handles_disconnected_graph():
    graph = {
        "A": ["B"],
        "B": [],
        "C": ["D"],
        "D": [],
    }

    result = topological_sort(graph)

    assert set(result) == {"A", "B", "C", "D"}
    assert result.index("A") < result.index("B")
    assert result.index("C") < result.index("D")


def test_topological_sort_ignores_missing_neighbor_keys():
    graph = {
        "A": ["B"],  # B is not explicitly defined in graph
    }

    result = topological_sort(graph)

    assert result == ["A", "B"]


def test_topological_sort_cycle_does_not_raise_but_returns_order():
    graph = {
        "A": ["B"],
        "B": ["A"],
    }

    result = topological_sort(graph)

    assert set(result) == {"A", "B"}
    assert len(result) == 2


def test_topological_sort_self_loop_does_not_raise_but_returns_single_node():
    graph = {
        "A": ["A"],
    }

    result = topological_sort(graph)

    assert result == ["A"]


def test_topological_sort_invalid_input_none():
    with pytest.raises(AttributeError):
        topological_sort(None)


def test_topological_sort_invalid_input_list():
    with pytest.raises(AttributeError):
        topological_sort([("A", ["B"])])


